def solve(n: Long, edges: Array[Array[Long]]): Long = {
  import scala.collection.mutable.PriorityQueue
  import scala.collection.mutable.ArrayBuffer

  val adj = Array.ofDim[Array[(Long, Long)]](n.toInt)
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val w = edge(2)
    adj(u) = adj(u) :+ (v, w)
  }

  val dist = Array.ofDim[Long](n.toInt, 2)
  for (i <- 0 until n.toInt) {
    dist(i)(0) = Long.MaxValue
    dist(i)(1) = Long.MaxValue
  }
  dist(0)(0) = 0

  val pq = PriorityQueue[(Long, (Long, Boolean))](Ordering.by(_._1))
  pq.enqueue((0, (0, false)))

  while (pq.nonEmpty) {
    val (cost, (u, switchUsed)) = pq.dequeue()
    if (u == n - 1) return cost
    if (cost > dist(u.toInt)(if (switchUsed) 1 else 0)) continue

    for ((v, w) <- adj(u.toInt)) {
      val newCost = cost + w
      if (newCost < dist(v)(if (switchUsed) 1 else 0)) {
        dist(v)(if (switchUsed) 1 else 0) = newCost
        pq.enqueue((newCost, (v, switchUsed)))
