def solve(n: Long, edges: Array[Array[Long]]): Long = {
  import scala.collection.mutable.{PriorityQueue, ArrayBuffer}

  val adj = ArrayBuffer[ArrayBuffer[(Long, Long)]]()
  for (i <- 0 until n) {
    adj += ArrayBuffer[(Long, Long)]()
  }

  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    adj(u) += ((v, w))
  }

  val dist = Array.ofDim[Long](n.toInt, 2)
  for (i <- 0 until n) {
    dist(i)(0) = Long.MaxValue
    dist(i)(1) = Long.MaxValue
  }
  dist(0)(0) = 0

  val pq = PriorityQueue[(Long, Long, Boolean)]()
  pq += (0, 0, false)

  while (pq.nonEmpty) {
    val (cost, u, switchUsed) = pq.pop()
    if (u == n - 1) return cost
    if (cost > dist(u.toInt)(if (switchUsed) 1 else 0)) continue

    for ((v, w) <- adj(u.toInt)) {
      val newCost = cost + w
      if (newCost < dist(v.toInt)(if (switchUsed) 1 else 0)) {
        dist(v.toInt)(if (switchUsed) 1 else 0) = newCost
        pq += (newCost, v, switchUsed)
      }
    }

    if (!switchUsed) {
      val newCost = cost + 2 * w
      if (newCost < dist(u.toInt)(1)) {
        dist(u.toInt)(1) = newCost
        pq += (newCost, u, true)
      }
    }
  }

  -1
}
